def count_words(filename):
    try:
        with open(filename, 'r') as file:
            content = file.read()
            words = content.split()
            return len(words)
    except FileNotFoundError:
        print(f'File {filename} not found')
        return 0
    except Exception as e:
        print(f'Error: {e}')
        return 0

# Usage
word_count = count_words('document.txt')
print(f'Total words: {word_count}')
